#contentSection { margin: 0.6em; font-size: 14px; }

#contentSection table { width: 520px; font-family: "Georgia", "Helvetica", Arial; font-size: 12px; border-collapse: collapse; background-color: #fafafa; }

#contentSection td.header { height: 85px; background-color: #005bbf; }

#contentSection td.body { padding: 22px; color: #151515; line-height: 23px; font-family: "Georgia", "Helvetica", Arial, sans-serif; text-align: right; }

#contentSection a.link { background: #005bbf; padding: 6px; color: #ffffff; display: block; text-decoration: none; }

#contentSection td.footer { text-align: center; padding: 11px; background-color: #f0f0f0; }

